// src/pages/NewsPage.jsx
import React, { useEffect, useState } from "react";
import api from "../api/backend";

const NewsPage = () => {
  const [articles, setArticles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchNews = async () => {
      try {
        const res = await api.get("/market-news");
        setArticles(res.data || []);
      } catch (err) {
        console.error(err);
        setError("Failed to load news.");
      } finally {
        setLoading(false);
      }
    };
    fetchNews();
  }, []);

  return (
    <div className="page-shell">
      <header className="header">
        <h1>Market News</h1>
        <p>Latest headlines from Yahoo Finance.</p>
      </header>

      <section className="results-panel">
        {loading && <p className="placeholder">Fetching latest news…</p>}
        {error && <div className="error-box">{error}</div>}

        {!loading && !error && (
          <div className="news-list">
            {articles.map((a, idx) => (
              <article key={idx} className="news-card">
                <div className="news-meta">
                  <span className="news-source">{a.source}</span>
                  {a.published && (
                    <span className="news-time">{a.published}</span>
                  )}
                </div>
                <a
                  href={a.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="news-title"
                >
                  {a.title}
                </a>
                {a.summary && <p className="news-summary">{a.summary}</p>}
              </article>
            ))}
          </div>
        )}
      </section>
    </div>
  );
};

export default NewsPage;
